import { getConfig } from "@/lib/config";
import { runHornsOnce } from "@/lib/queue";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";
export const maxDuration = 300;

function isAuthorized(request: Request, cronSecret?: string) {
  if (!cronSecret) {
    return true;
  }

  const authHeader = request.headers.get("authorization");
  if (authHeader === `Bearer ${cronSecret}`) {
    return true;
  }

  const requestUrl = new URL(request.url);
  return requestUrl.searchParams.get("secret") === cronSecret;
}

function errorMessage(error: unknown) {
  return error instanceof Error ? error.message : String(error);
}

export async function GET(request: Request) {
  try {
    const config = getConfig();

    if (!isAuthorized(request, config.cronSecret)) {
      return Response.json({ error: "Unauthorized" }, { status: 401 });
    }

    const result = await runHornsOnce("vercel-cron");
    return Response.json(result);
  } catch (error) {
    console.error("horns.cron.failed", error);
    return Response.json({ error: errorMessage(error) }, { status: 500 });
  }
}

export const POST = GET;
